import{_ as t,o as l,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F09: 毛利變動與經營槓桿審計 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3105_穩懋/20260503/F09_毛利變動與經營槓桿審計.md","filePath":"審計報告庫/財務審計/3105_穩懋/20260503/F09_毛利變動與經營槓桿審計.md"}'),i={name:"審計報告庫/財務審計/3105_穩懋/20260503/F09_毛利變動與經營槓桿審計.md"};function e(n,a,s,h,d,_){return l(),r("div",null,[...a[0]||(a[0]=[o('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f09-毛利變動與經營槓桿審計-財務審計專家-審計報告" tabindex="-1">F09: 毛利變動與經營槓桿審計 - 財務審計專家 審計報告 <a class="header-anchor" href="#f09-毛利變動與經營槓桿審計-財務審計專家-審計報告" aria-label="Permalink to &quot;F09: 毛利變動與經營槓桿審計 - 財務審計專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>毛利率 (GM)、營業利益率 (OPM) 與淨利率的連動關係為何？是否存在經營槓桿放大或侵蝕損益的現象？分析三率趨勢判定定價權與成本控管能力。</p></blockquote><h2 id="🎯-專家直斷-48-字" tabindex="-1">🎯 專家直斷（48 字） <a class="header-anchor" href="#🎯-專家直斷-48-字" aria-label="Permalink to &quot;🎯 專家直斷（48 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：GM 連三年升至 24.2%（產品組合優化），但 OPM 停滯 4.3%，費用率反彈至 19.9%。DOL 3.69 正向但利用率未滿載致槓桿受限。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至 2025 年最新公開數據</li></ul><h2 id="📊-診斷評級-136-字" tabindex="-1">📊 診斷評級（136 字） <a class="header-anchor" href="#📊-診斷評級-136-字" aria-label="Permalink to &quot;📊 診斷評級（136 字）&quot;">​</a></h2><ul><li><strong>重點數據</strong>：GM 21.9%→24.2%（+2.3pp），OPM -0.4%→4.3%，OpEx/營收比 22.3%→19.9%。Cost Ratio 78.1%→75.8%。Q4 GM 跳升至 31.8%。</li><li><strong>診斷見解</strong>：GM 改善來自產品組合升級，惟營收縮減致 OpEx 率僵固。Q4 GM 強勁若延續 OPM 有望突破 10%。</li></ul><h2 id="🔍-答詢詳解-432-字" tabindex="-1">🔍 答詢詳解（432 字） <a class="header-anchor" href="#🔍-答詢詳解-432-字" aria-label="Permalink to &quot;🔍 答詢詳解（432 字）&quot;">​</a></h2><h3 id="三率趨勢-gm-改善但-opm-停滯" tabindex="-1">三率趨勢：GM 改善但 OPM 停滯 <a class="header-anchor" href="#三率趨勢-gm-改善但-opm-停滯" aria-label="Permalink to &quot;三率趨勢：GM 改善但 OPM 停滯&quot;">​</a></h3><ul><li><strong>核心重點</strong>：GM 升 2.3pp、Cost Ratio 降 2.3pp 驗證升級。OPM 從 4.4% 微降至 4.3%，主因 OpEx 率從 18.8% 反彈至 19.9%。</li><li><strong>深度見解</strong>：NPM（1.9%→6.5%）含一次性業外，核心 NPM 約 3.5-4.5%。OPM 4.3% 在代工業處中段。</li></ul><h3 id="經營槓桿檢驗-雙向不對稱效應" tabindex="-1">經營槓桿檢驗：雙向不對稱效應 <a class="header-anchor" href="#經營槓桿檢驗-雙向不對稱效應" aria-label="Permalink to &quot;經營槓桿檢驗：雙向不對稱效應&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2024 年 DOL 3.69（營收+10.2%推升營益），2025 年 DOL -0.1。固定成本約佔 50-55%。</li><li><strong>深度見解</strong>：固定成本高使利用率提升時利潤增速快，反轉亦快。2023 年營益率 -0.4% 為實證。2026 年利用率 65-70% 時營益率可擴至 8-10%。</li></ul><h3 id="費用結構-r-d-的戰略性投入" tabindex="-1">費用結構：R&amp;D 的戰略性投入 <a class="header-anchor" href="#費用結構-r-d-的戰略性投入" aria-label="Permalink to &quot;費用結構：R&amp;D 的戰略性投入&quot;">​</a></h3><ul><li><strong>核心重點</strong>：R&amp;D $1,600M（營收比 9.6%）&gt; 管理費 $1,259M（7.6%）&gt; 銷售費 $449M（2.7%），R&amp;D 連續三年維持戰略性投入。</li><li><strong>深度見解</strong>：R&amp;D 強度 9.6% 在同業合理區間，有助支撐 GM 結構性改善。</li></ul><h2 id="💡-專家評析-413-字-≥2-個利空關鍵字" tabindex="-1">💡 專家評析（413 字，≥2 個利空關鍵字） <a class="header-anchor" href="#💡-專家評析-413-字-≥2-個利空關鍵字" aria-label="Permalink to &quot;💡 專家評析（413 字，≥2 個利空關鍵字）&quot;">​</a></h2><ol><li><p><strong>費用僵固性導致營益率天花板明顯</strong>：穩懋 OpEx NT$3.3B 中，管理費用 NT$1.26B 與研發費用 NT$1.60B 屬高固定性質。即使 2026 年營收回升至 NT$18-19B，OpEx 率仍將維持在 18-19%，GM 需達到 28-30% 才能實現 OPM 雙位數。2025 年 Q4 GM 31.8% 雖具鼓舞效果，但此為旺季效應下的產品組合極值，全年能否常態化仍存在不確定性壓力。</p></li><li><p><strong>2025 年營益率停滯反映營收規模不足</strong>：2025 年營收 NT$16.64B 僅為 2022 年歷史高峰（約 NT$23-24B）的 69-72%。營收規模縮減直接削弱了固定成本攤提基礎。2024 年營收 17.46B 時 OPM 4.4%，2025 年營收 16.64B 時 OPM 4.3%，幾乎與營收同步變化。若營收無法在 2026 年重返 NT$20B 以上，OPM 向上突破 8% 的難度大增。</p></li><li><p><strong>NPM 與 OPM 差距被業外一次性項目扭曲</strong>：2025 年 NPM 6.5% 與 OPM 4.3% 的差距達 2.2pp，主因業外淨利 NT$672M 貢獻。其中 NT$1.95B 資產處分利益與 NT$1.64B 減損損失對沖後淨貢獻一次性（約佔稅前 22%）。剔除一次性項目後核心 NPM 僅 3.5-4.5%，與 OPM 接近。若以核心獲利計算，目前股價本益比遠高於帳面顯示之水準，估值壓力不容忽視。</p></li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (margin_analysis 3105 2023 2025)、(cost_structure 3105 2023 2025)</li><li>原始數據：FinMind TaiwanStockFinancialStatements</li><li>年報 PDF：2025_Q4_3105_合併.pdf（合併綜合損益表 p.9）</li><li>查詢參數：stock_id=3105, start=2023-01-01, end=2025-12-31</li><li>關鍵核對碼：GM 24.2%=4,026,093/16,638,534, OPM 4.3%=714,702/16,638,534, NPM 6.5%=1,089,818/16,638,534</li></ul>',19)])])}const c=t(i,[["render",e]]);export{u as __pageData,c as default};
